import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    out = []
    idx = 1
    for _ in range(t):
        a = int(data[idx]); b = int(data[idx+1]); c = int(data[idx+2])
        idx += 3
        if a < b < c:
            out.append("Increasing")
        elif a > b > c:
            out.append("Decreasing")
        else:
            out.append("Neither")
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    solve()

